solutions.python:
class Solution:
    def isSumEqual(self, firstWord, secondWord, targetWord):
        def val(w):
            n = 0
            for c in w:
                n = n * 10 + (ord(c) - 97)
            return n
        return val(firstWord) + val(secondWord) == val(targetWord)

