var isSumEqual = function(firstWord, secondWord, targetWord) {
    const val = w => {
        let n = 0;
        for (const c of w) n = n * 10 + (c.charCodeAt(0) - 97);
        return n;
    };
    return val(firstWord) + val(secondWord) === val(targetWord);
};
